@use 'sass:map'
@use '../../styles/settings'
@use '../../styles/tools'

@mixin make-container($padding-x: settings.$container-padding-x)
  width: 100%
  padding: $padding-x
  margin-right: auto
  margin-left: auto

// For each breakpoint, define the maximum width of the container in a media query
@mixin make-container-max-widths
  $max-widths: settings.$container-max-widths
  $breakpoints: settings.$grid-breakpoints
  @each $breakpoint, $container-max-width in $max-widths
    @include tools.media-breakpoint-up($breakpoint, $breakpoints)
      max-width: $container-max-width

@mixin make-grid-columns
  $breakpoints: settings.$grid-breakpoints
  @each $breakpoint in map.keys($breakpoints)
    $infix: tools.breakpoint-infix($breakpoint, $breakpoints)

    @include tools.media-breakpoint-up($breakpoint, $breakpoints)
      @content($infix)

// Calculate the total sum of a list (context)
@function list-sum($list)
  // zero out the initial sum
  $sum: 0
  // loop through each value in the list adding it to $list-sum
  @for $i from 1 through length($list)
    $sum: $sum + nth(nth($list, $i), 1)
  @return nth($sum, 1)


// Find column count
@function column-count($columns)
  @if type-of($columns) == number
    @return $columns
  @if type-of($columns) == list
    @return length($columns)


// Context of gutters
@function gutter-context($gutter, $context)
  @return $gutter * (100% / $context)

@function repeat($count, $repeat)
  $list: $repeat
  @for $i from 2 through $count
    $list: join($repeat, $list)
  @return $list

// Reverses direction of a list
@function reverse($list)
  $length: length($list)
  $return: ()

  @for $i from 0 to $length
    $return: append($return, nth($list, $length - $i), comma)

  @return $return

@use 'sass:map'
@use '../../styles/settings'
@use '../../styles/tools'
@use './variables' as *

// Transition
@include tools.layer('transitions')
  .bottom-sheet-transition
    &-enter-active, &-leave-active
      transition-property: transform
      pointer-events: none

    &-enter-from, &-leave-to
      transform: translateY(100%)

// Block
@include tools.layer('components')
  .v-bottom-sheet
    > .v-bottom-sheet__content.v-overlay__content
      align-self: flex-end
      border-radius: 0
      flex: 0 1 auto
      left: 0
      right: 0
      margin-inline: auto
      margin-bottom: 0
      transition-duration: $bottom-sheet-transition-duration
      width: 100%
      max-width: 100%
      overflow: visible

      @include tools.elevation($bottom-sheet-elevation)

      @media (prefers-reduced-motion: reduce)
        transition: none

      > .v-card,
      > .v-sheet
        border-radius: $bottom-sheet-border-radius

    &.v-bottom-sheet--inset
      max-width: none

      @media #{map.get(settings.$display-breakpoints, 'sm-and-up')}
        max-width: $bottom-sheet-inset-width

@mixin inline-block
  display:  inline-block

@mixin center-block
  +block
  margin-left: auto
  margin-right: auto

@mixin block
  display: block

@mixin inline
  display: inline

@mixin absolute
  position: absolute

@mixin abs-pos ($top: auto, $right: auto, $bottom: auto, $left: auto)
  +absolute
  top: $top
  right: $right
  bottom: $bottom
  left: $left

@mixin relative
  position: relative

@mixin fixed
  position: fixed

@mixin static
  position: static

@mixin left
  float: left

@mixin right
  float: right

@mixin flip-horizontal
  -moz-transform: scaleX(-1)
  -o-transform: scaleX(-1)
  -webkit-transform: scaleX(-1)
  transform: scaleX(-1)
  filter: FlipV

@mixin flip-vertical
  -moz-transform: scaleY(-1)
  -o-transform: scaleY(-1)
  -webkit-transform: scaleY(-1)
  transform: scaleY(-1)
  filter: FlipH

@mixin with-woocommerce-breadcrumb
	.woocommerce-breadcrumb
		@content

@mixin with-woocommerce-products
	.woocommerce
		.products
			@content

@mixin with-product
	.product
		@content

@mixin with-product-image
	.et_shop_image
		@content

@mixin with-product-image-icon-overlay
	+with-product-image
		.et_overlay
			@content

//single-product
@mixin with-woocommerce-single-product
	body.single-product
		@content

@mixin with-product
	.product
		@content

@mixin with-product-gallery
	.woocommerce-product-gallery
		@content

@mixin with-product-summary
	.summary
		@content

@mixin with-summary-title
	.product_title
		@content

@mixin with-summary-meta
	.product_meta
		@content

@mixin with-product-tabs
	.woocommerce-tabs
		@content

@mixin with-wc-tabs
	ul.wc-tabs.tabs
		@content

@mixin with-tabs-panel
	.woocommerce-Tabs-panel
		@content
